 28→func newResumeCmd() *cobra.Command {
 29→	var force bool
 30→
 31→	cmd := &cobra.Command{
 32→		Use:   "resume <branch>",
 33→		Short: "Switch to a branch and resume its session",
 34→		Long: `Switch to a local branch and resume the agent session from its last commit.
 35→
 36→This command:
 37→1. Checks out the specified branch
 38→2. Finds the session ID from commits unique to this branch (not on main)
 39→3. Restores the session log if it doesn't exist locally
 40→4. Shows the command to resume the session
 41→
 42→If the branch doesn't exist locally but exists on origin, you'll be prompted
 43→to fetch it.
 44→
 45→If newer commits without checkpoints exist on the branch (e.g., after merging main
 46→or cherry-picking from elsewhere), this operation will reset your Git status to the
 47→most recent commit with a checkpoint.  You'll be prompted to confirm resuming in this case.`,
 48→		Args: cobra.ExactArgs(1),
 49→		RunE: func(cmd *cobra.Command, args []string) error {
 50→			if checkDisabledGuard(cmd.Context(), cmd.OutOrStdout()) {
 51→				return nil
 52→			}
 53→			return runResume(cmd.Context(), args[0], force)
 54→		},
 55→	}
 56→
 57→	cmd.Flags().BoolVarP(&force, "force", "f", false, "Resume from older checkpoint without confirmation")
 58→
 59→	return cmd
 60→}
