 62→func runResume(ctx context.Context, branchName string, force bool) error {
 63→	// Check if we're already on this branch
 64→	currentBranch, err := GetCurrentBranch(ctx)
 65→	if err == nil && currentBranch == branchName {
 66→		// Already on the branch, skip checkout
 67→		return resumeFromCurrentBranch(ctx, branchName, force)
 68→	}
 69→
 70→	// Check if branch exists locally
 71→	exists, err := BranchExistsLocally(ctx, branchName)
 72→	if err != nil {
 73→		return fmt.Errorf("failed to check branch: %w", err)
 74→	}
 75→
 76→	if !exists {
 77→		// Branch doesn't exist locally, check if it exists on remote
 78→		remoteExists, err := BranchExistsOnRemote(ctx, branchName)
 79→		if err != nil {
 80→			return fmt.Errorf("failed to check remote branch: %w", err)
 81→		}
 82→
 83→		if !remoteExists {
 84→			return fmt.Errorf("branch '%s' not found locally or on origin", branchName)
 85→		}
 86→
 87→		// Ask user if they want to fetch from remote
 88→		shouldFetch, err := promptFetchFromRemote(branchName)
 89→		if err != nil {
 90→			return err
 91→		}
 92→		if !shouldFetch {
 93→			return nil
 94→		}
 95→
 96→		// Fetch and checkout the remote branch
 97→		fmt.Fprintf(os.Stderr, "Fetching branch '%s' from origin...\n", branchName)
 98→		if err := FetchAndCheckoutRemoteBranch(ctx, branchName); err != nil {
 99→			fmt.Fprintf(os.Stderr, "Failed to checkout branch: %v\n", err)
100→			return NewSilentError(errors.New("failed to checkout branch"))
101→		}
102→		fmt.Fprintf(os.Stderr, "Switched to branch '%s'\n", branchName)
103→	} else {
104→		// Branch exists locally, check for uncommitted changes before checkout
105→		hasChanges, err := HasUncommittedChanges(ctx)
106→		if err != nil {
107→			return fmt.Errorf("failed to check for uncommitted changes: %w", err)
108→		}
109→		if hasChanges {
110→			return errors.New("you have uncommitted changes. Please commit or stash them first")
111→		}
112→
113→		// Checkout the branch
114→		if err := CheckoutBranch(ctx, branchName); err != nil {
115→			fmt.Fprintf(os.Stderr, "Failed to checkout branch: %v\n", err)
116→			return NewSilentError(errors.New("failed to checkout branch"))
117→		}
118→		fmt.Fprintf(os.Stderr, "Switched to branch '%s'\n", branchName)
119→	}
120→
121→	return resumeFromCurrentBranch(ctx, branchName, force)
122→}
