124→func resumeFromCurrentBranch(ctx context.Context, branchName string, force bool) error {
125→	repo, err := openRepository(ctx)
126→	if err != nil {
127→		return fmt.Errorf("not a git repository: %w", err)
128→	}
129→
130→	// Find a commit with an Entire-Checkpoint trailer, looking at branch-only commits
131→	result, err := findBranchCheckpoints(repo, branchName)
132→	if err != nil {
133→		return err
134→	}
135→	if len(result.checkpointIDs) == 0 {
136→		fmt.Fprintf(os.Stderr, "No Entire checkpoint found on branch '%s'\n", branchName)
137→		return nil
138→	}
139→
140→	// If there are newer commits without checkpoints, ask for confirmation.
141→	// Merge commits (e.g., from merging main) don't count as "work" and are skipped silently.
142→	if result.newerCommitsExist && !force {
143→		fmt.Fprintf(os.Stderr, "Found checkpoint in an older commit.\n")
144→		fmt.Fprintf(os.Stderr, "There are %d newer commit(s) on this branch without checkpoints.\n", result.newerCommitCount)
145→		fmt.Fprintf(os.Stderr, "Checkpoint from: %s %s\n\n", result.commitHash[:7], firstLine(result.commitMessage))
146→
147→		shouldResume, err := promptResumeFromOlderCheckpoint()
148→		if err != nil {
149→			return err
150→		}
151→		if !shouldResume {
152→			fmt.Fprintf(os.Stderr, "Resume cancelled.\n")
153→			return nil
154→		}
155→	}
156→
157→	// Multiple checkpoints (squash merge): restore all sessions
158→	if len(result.checkpointIDs) > 1 {
159→		return resumeMultipleCheckpoints(ctx, repo, result.checkpointIDs, force)
160→	}
161→
162→	// Single checkpoint: existing behavior (unchanged)
163→	checkpointID := result.checkpointIDs[0]
164→
165→	// Get metadata branch tree for lookups
166→	metadataTree, err := strategy.GetMetadataBranchTree(repo)
167→	if err != nil {
168→		// No local metadata branch, check if remote has it
169→		return checkRemoteMetadata(ctx, repo, checkpointID)
170→	}
171→
172→	// Look up metadata from sharded path
173→	metadata, err := strategy.ReadCheckpointMetadata(metadataTree, checkpointID.Path())
174→	if err != nil {
175→		// Checkpoint exists in commit but no local metadata - check remote
176→		return checkRemoteMetadata(ctx, repo, checkpointID)
177→	}
178→
179→	return resumeSession(ctx, metadata.SessionID, checkpointID, force)
180→}
181→
182→// resumeMultipleCheckpoints restores sessions from multiple checkpoint IDs.
183→// This handles squash merge commits where multiple Entire-Checkpoint trailers
184→// are present in a single commit message. Each checkpoint is looked up independently
185→// and missing metadata is skipped (best-effort).
186→func resumeMultipleCheckpoints(ctx context.Context, repo *git.Repository, checkpointIDs []id.CheckpointID, force bool) error {
187→	logCtx := logging.WithComponent(ctx, "resume")
188→
189→	// Get metadata branch tree (try local first, then remote)
190→	metadataTree, err := strategy.GetMetadataBranchTree(repo)
191→	if err != nil {
192→		// Try fetching from remote
193→		logging.Debug(logCtx, "metadata branch not available locally, trying remote")
194→		if fetchErr := FetchMetadataBranch(ctx); fetchErr != nil {
195→			// If fetch also fails, try remote tree directly
196→			remoteTree, remoteErr := strategy.GetRemoteMetadataBranchTree(repo)
197→			if remoteErr != nil {
198→				fmt.Fprintf(os.Stderr, "Checkpoint metadata not available locally or on remote\n")
199→				return nil //nolint:nilerr // Informational message, not a fatal error
200→			}
201→			metadataTree = remoteTree
202→		} else {
203→			metadataTree, err = strategy.GetMetadataBranchTree(repo)
204→			if err != nil {
205→				fmt.Fprintf(os.Stderr, "Checkpoint metadata not available after fetch\n")
206→				return nil //nolint:nilerr // Informational message, not a fatal error
207→			}
208→		}
209→	}
210→
211→	// Read metadata for all checkpoints and sort by CreatedAt ascending
212→	// (oldest first → newest writes last and wins on disk)
213→	checkpoints := collectCheckpointsByAge(metadataTree, checkpointIDs)
214→
215→	// Iterate sorted checkpoints and restore
216→	strat := GetStrategy(ctx)
217→	var allSessions []strategy.RestoredSession
218→
219→	for _, cp := range checkpoints {
220→		point := strategy.RewindPoint{
221→			IsLogsOnly:   true,
222→			CheckpointID: cp.CheckpointID,
223→			Agent:        cp.Agent,
224→		}
225→
226→		sessions, restoreErr := strat.RestoreLogsOnly(ctx, point, force)
227→		if restoreErr != nil {
228→			logging.Debug(logCtx, "skipping checkpoint: restore failed",
229→				slog.String("checkpoint_id", cp.CheckpointID.String()),
230→				slog.String("error", restoreErr.Error()),
231→			)
232→			continue
233→		}
234→		if len(sessions) == 0 {
235→			logging.Debug(logCtx, "skipping checkpoint: no sessions restored",
236→				slog.String("checkpoint_id", cp.CheckpointID.String()),
237→			)
238→			continue
239→		}
240→
241→		allSessions = deduplicateSessions(allSessions, sessions)
242→	}
243→
244→	if len(allSessions) == 0 {
245→		fmt.Fprintf(os.Stderr, "No session metadata found for checkpoints in this commit\n")
246→		return nil
247→	}
248→
249→	logging.Debug(logCtx, "resume multiple checkpoints completed",
250→		slog.Int("checkpoint_count", len(checkpointIDs)),
251→		slog.Int("session_count", len(allSessions)),
252→	)
253→
254→	return displayRestoredSessions(allSessions)
255→}
256→
257→// collectCheckpointsByAge reads metadata for each checkpoint ID from the tree,
258→// skips any that can't be read, and returns them sorted by CreatedAt ascending.
259→// Sorting ensures the newest checkpoint is restored last and wins on disk,
260→// regardless of trailer order in the commit message.
261→func collectCheckpointsByAge(tree *object.Tree, checkpointIDs []id.CheckpointID) []*strategy.CheckpointInfo {
262→	var checkpoints []*strategy.CheckpointInfo
263→	for _, cpID := range checkpointIDs {
264→		metadata, err := strategy.ReadCheckpointMetadata(tree, cpID.Path())
265→		if err != nil {
266→			continue
267→		}
268→		checkpoints = append(checkpoints, metadata)
269→	}
270→	sort.Slice(checkpoints, func(i, j int) bool {
271→		return checkpoints[i].CreatedAt.Before(checkpoints[j].CreatedAt)
272→	})
273→	return checkpoints
274→}
