276→// deduplicateSessions merges new sessions into existing, keeping the one with the latest
277→// CreatedAt when a SessionID appears more than once. This handles squash merges where the
278→// same session may be referenced by multiple checkpoints.
279→func deduplicateSessions(existing, incoming []strategy.RestoredSession) []strategy.RestoredSession {
280→	type entry struct {
281→		index     int
282→		createdAt time.Time
283→	}
284→
285→	seen := make(map[string]entry, len(existing))
286→	for i, s := range existing {
287→		seen[s.SessionID] = entry{index: i, createdAt: s.CreatedAt}
288→	}
289→
290→	for _, sess := range incoming {
291→		if prev, exists := seen[sess.SessionID]; exists {
292→			// Keep the one with the later CreatedAt (more complete transcript)
293→			if sess.CreatedAt.After(prev.createdAt) {
294→				existing[prev.index] = sess
295→				seen[sess.SessionID] = entry{index: prev.index, createdAt: sess.CreatedAt}
296→			}
297→		} else {
298→			seen[sess.SessionID] = entry{index: len(existing), createdAt: sess.CreatedAt}
299→			existing = append(existing, sess)
300→		}
301→	}
302→
303→	return existing
304→}
