306→// branchCheckpointsResult contains the result of searching for checkpoints on a branch.
307→type branchCheckpointsResult struct {
308→	checkpointIDs     []id.CheckpointID
309→	commitHash        string
310→	commitMessage     string
311→	newerCommitsExist bool // true if there are branch-only commits (not merge commits) without checkpoints
312→	newerCommitCount  int  // count of branch-only commits without checkpoints
313→}
314→
315→// findBranchCheckpoints finds the most recent commit with an Entire-Checkpoint trailer
316→// among commits that are unique to this branch (not reachable from the default branch).
317→// This handles the case where main has been merged into the feature branch.
318→func findBranchCheckpoints(repo *git.Repository, branchName string) (*branchCheckpointsResult, error) {
319→	result := &branchCheckpointsResult{}
320→
321→	// Get HEAD commit
322→	head, err := repo.Head()
323→	if err != nil {
324→		return nil, fmt.Errorf("failed to get HEAD: %w", err)
325→	}
326→
327→	headCommit, err := repo.CommitObject(head.Hash())
328→	if err != nil {
329→		return nil, fmt.Errorf("failed to get HEAD commit: %w", err)
330→	}
331→
332→	// First, check if HEAD itself has a checkpoint (most common case)
333→	if cpIDs := trailers.ParseAllCheckpoints(headCommit.Message); len(cpIDs) > 0 {
334→		result.checkpointIDs = cpIDs
335→		result.commitHash = head.Hash().String()
336→		result.commitMessage = headCommit.Message
337→		result.newerCommitsExist = false
338→		return result, nil
339→	}
340→
341→	// HEAD doesn't have a checkpoint - find branch-only commits
342→	// Get the default branch name
343→	defaultBranch := getDefaultBranchFromRemote(repo)
344→	if defaultBranch == "" {
345→		// Fallback: try common names
346→		for _, name := range []string{"main", "master"} {
347→			if _, err := repo.Reference(plumbing.NewBranchReferenceName(name), true); err == nil {
348→				defaultBranch = name
349→				break
350→			}
351→		}
352→	}
353→
354→	// If we can't find a default branch, or we're on it, just walk all commits
355→	if defaultBranch == "" || defaultBranch == branchName {
356→		return findCheckpointInHistory(headCommit, nil), nil
357→	}
358→
359→	// Get the default branch reference
360→	defaultRef, err := repo.Reference(plumbing.NewBranchReferenceName(defaultBranch), true)
361→	if err != nil {
362→		// Default branch doesn't exist locally, fall back to walking all commits
363→		return findCheckpointInHistory(headCommit, nil), nil //nolint:nilerr // Intentional fallback
364→	}
365→
366→	defaultCommit, err := repo.CommitObject(defaultRef.Hash())
367→	if err != nil {
368→		// Can't get default commit, fall back to walking all commits
369→		return findCheckpointInHistory(headCommit, nil), nil //nolint:nilerr // Intentional fallback
370→	}
371→
372→	// Find merge base
373→	mergeBase, err := headCommit.MergeBase(defaultCommit)
374→	if err != nil || len(mergeBase) == 0 {
375→		// No common ancestor, fall back to walking all commits
376→		return findCheckpointInHistory(headCommit, nil), nil //nolint:nilerr // Intentional fallback
377→	}
378→
379→	// Walk from HEAD to merge base, looking for checkpoint
380→	return findCheckpointInHistory(headCommit, &mergeBase[0].Hash), nil
381→}
382→
383→// findCheckpointInHistory walks commit history from start looking for a checkpoint trailer.
384→// If stopAt is provided, stops when reaching that commit (exclusive).
385→// Returns the first checkpoint found and info about commits between HEAD and the checkpoint.
386→// It distinguishes between merge commits (bringing in other branches) and regular commits
387→// (actual branch work) to avoid false warnings after merging main.
388→func findCheckpointInHistory(start *object.Commit, stopAt *plumbing.Hash) *branchCheckpointsResult {
389→	result := &branchCheckpointsResult{}
390→	branchWorkCommits := 0 // Regular commits without checkpoints (actual work)
391→	const maxCommits = 100 // Limit search depth
392→	totalChecked := 0
393→
394→	current := start
395→	for current != nil && totalChecked < maxCommits {
396→		// Stop if we've reached the boundary
397→		if stopAt != nil && current.Hash == *stopAt {
398→			break
399→		}
400→
401→		// Check for checkpoint trailer
402→		if cpIDs := trailers.ParseAllCheckpoints(current.Message); len(cpIDs) > 0 {
403→			result.checkpointIDs = cpIDs
404→			result.commitHash = current.Hash.String()
405→			result.commitMessage = current.Message
406→			// Only warn about branch work commits, not merge commits
407→			result.newerCommitsExist = branchWorkCommits > 0
408→			result.newerCommitCount = branchWorkCommits
409→			return result
410→		}
411→
412→		// Only count regular commits (not merge commits) as "branch work"
413→		if current.NumParents() <= 1 {
414→			branchWorkCommits++
415→		}
416→
417→		totalChecked++
418→
419→		// Move to parent (first parent for merge commits - follows the main line)
420→		if current.NumParents() == 0 {
421→			break
422→		}
423→		parent, err := current.Parent(0)
424→		if err != nil {
425→			// Can't get parent, treat as end of history
426→			break
427→		}
428→		current = parent
429→	}
430→
431→	// No checkpoint found
432→	return result
433→}
