435→// promptResumeFromOlderCheckpoint asks the user if they want to resume from an older checkpoint.
436→func promptResumeFromOlderCheckpoint() (bool, error) {
437→	var confirmed bool
438→
439→	form := NewAccessibleForm(
440→		huh.NewGroup(
441→			huh.NewConfirm().
442→				Title("Resume from this older checkpoint?").
443→				Value(&confirmed),
444→		),
445→	)
446→
447→	if err := form.Run(); err != nil {
448→		if errors.Is(err, huh.ErrUserAborted) {
449→			return false, nil
450→		}
451→		return false, fmt.Errorf("failed to get confirmation: %w", err)
452→	}
453→
454→	return confirmed, nil
455→}
