457→// checkRemoteMetadata checks if checkpoint metadata exists on origin/entire/checkpoints/v1
458→// and automatically fetches it if available.
459→func checkRemoteMetadata(ctx context.Context, repo *git.Repository, checkpointID id.CheckpointID) error {
460→	// Try to get remote metadata branch tree
461→	remoteTree, err := strategy.GetRemoteMetadataBranchTree(repo)
462→	if err != nil {
463→		fmt.Fprintf(os.Stderr, "Checkpoint '%s' found in commit but session metadata not available\n", checkpointID)
464→		fmt.Fprintf(os.Stderr, "The entire/checkpoints/v1 branch may not exist locally or on the remote.\n")
465→		return nil //nolint:nilerr // Informational message, not a fatal error
466→	}
467→
468→	// Check if the checkpoint exists on the remote
469→	metadata, err := strategy.ReadCheckpointMetadata(remoteTree, checkpointID.Path())
470→	if err != nil {
471→		fmt.Fprintf(os.Stderr, "Checkpoint '%s' found in commit but session metadata not available\n", checkpointID)
472→		return nil //nolint:nilerr // Informational message, not a fatal error
473→	}
474→
475→	// Metadata exists on remote but not locally - fetch it automatically
476→	fmt.Fprintf(os.Stderr, "Fetching session metadata from origin...\n")
477→	if err := FetchMetadataBranch(ctx); err != nil {
478→		fmt.Fprintf(os.Stderr, "Failed to fetch metadata: %v\n", err)
479→		fmt.Fprintf(os.Stderr, "You can try manually: git fetch origin entire/checkpoints/v1:entire/checkpoints/v1\n")
480→		return NewSilentError(errors.New("failed to fetch metadata"))
481→	}
482→
483→	// Now resume the session with the fetched metadata
484→	return resumeSession(ctx, metadata.SessionID, checkpointID, false)
485→}
