487→// resumeSession restores and displays the resume command for a specific session.
488→// For multi-session checkpoints, restores ALL sessions and shows commands for each.
489→// If force is false, prompts for confirmation when local logs have newer timestamps.
490→func resumeSession(ctx context.Context, sessionID string, checkpointID id.CheckpointID, force bool) error {
491→	// Read checkpoint metadata first to get agent type (matching rewind pattern)
492→	repo, err := openRepository(ctx)
493→	if err != nil {
494→		return fmt.Errorf("failed to open repository: %w", err)
495→	}
496→
497→	metadataTree, err := strategy.GetMetadataBranchTree(repo)
498→	if err != nil {
499→		return fmt.Errorf("failed to get metadata branch: %w", err)
500→	}
501→
502→	metadata, err := strategy.ReadCheckpointMetadata(metadataTree, checkpointID.Path())
503→	if err != nil {
504→		return fmt.Errorf("failed to read checkpoint metadata: %w", err)
505→	}
506→
507→	// Resolve agent from checkpoint metadata (same as rewind)
508→	ag, err := strategy.ResolveAgentForRewind(metadata.Agent)
509→	if err != nil {
510→		return fmt.Errorf("failed to resolve agent: %w", err)
511→	}
512→
513→	// Initialize logging context with agent
514→	logCtx := logging.WithAgent(logging.WithComponent(ctx, "resume"), ag.Name())
515→
516→	logging.Debug(logCtx, "resume session started",
517→		slog.String("checkpoint_id", checkpointID.String()),
518→		slog.String("session_id", sessionID),
519→	)
520→
521→	// Get worktree root for session directory lookup
522→	repoRoot, err := paths.WorktreeRoot(ctx)
523→	if err != nil {
524→		return fmt.Errorf("failed to get worktree root: %w", err)
525→	}
526→
527→	sessionDir, err := ag.GetSessionDir(repoRoot)
528→	if err != nil {
529→		return fmt.Errorf("failed to determine session directory: %w", err)
530→	}
531→
532→	// Create directory if it doesn't exist
533→	if err := os.MkdirAll(sessionDir, 0o700); err != nil {
534→		return fmt.Errorf("failed to create session directory: %w", err)
535→	}
536→
537→	// Get strategy and restore sessions using full checkpoint data
538→	strat := GetStrategy(ctx)
539→
540→	// Use RestoreLogsOnly via LogsOnlyRestorer interface for multi-session support
541→	// Create a logs-only rewind point with Agent populated (same as rewind)
542→	point := strategy.RewindPoint{
543→		IsLogsOnly:   true,
544→		CheckpointID: checkpointID,
545→		Agent:        metadata.Agent,
546→	}
547→
548→	sessions, restoreErr := strat.RestoreLogsOnly(ctx, point, force)
549→	if restoreErr != nil || len(sessions) == 0 {
550→		// Fall back to single-session restore (e.g., old checkpoints without agent metadata)
551→		return resumeSingleSession(ctx, ag, sessionID, checkpointID, repoRoot, force)
552→	}
553→
554→	logging.Debug(logCtx, "resume session completed",
555→		slog.String("checkpoint_id", checkpointID.String()),
556→		slog.Int("session_count", len(sessions)),
557→	)
558→
559→	return displayRestoredSessions(sessions)
560→}
561→
562→// displayRestoredSessions sorts sessions by CreatedAt and prints resume commands.
563→// Used by both resumeSession (single checkpoint) and resumeMultipleCheckpoints (squash merge).
564→func displayRestoredSessions(sessions []strategy.RestoredSession) error {
565→	sort.SliceStable(sessions, func(i, j int) bool {
566→		return sessions[i].CreatedAt.Before(sessions[j].CreatedAt)
567→	})
568→
569→	if len(sessions) > 1 {
570→		fmt.Fprintf(os.Stderr, "\nRestored %d sessions. To continue, run:\n", len(sessions))
571→	} else if len(sessions) == 1 {
572→		fmt.Fprintf(os.Stderr, "Session: %s\n", sessions[0].SessionID)
573→		fmt.Fprintf(os.Stderr, "\nTo continue this session, run:\n")
574→	}
575→
576→	for i, sess := range sessions {
577→		sessionAgent, err := strategy.ResolveAgentForRewind(sess.Agent)
578→		if err != nil {
579→			return fmt.Errorf("failed to resolve agent for session %s: %w", sess.SessionID, err)
580→		}
581→		cmd := sessionAgent.FormatResumeCommand(sess.SessionID)
582→
583→		isLast := i == len(sessions)-1
584→		switch {
585→		case len(sessions) > 1 && isLast && sess.Prompt != "":
586→			fmt.Fprintf(os.Stderr, "  %s  # %s (most recent)\n", cmd, sess.Prompt)
587→		case len(sessions) > 1 && isLast:
588→			fmt.Fprintf(os.Stderr, "  %s  # (most recent)\n", cmd)
589→		case sess.Prompt != "":
590→			fmt.Fprintf(os.Stderr, "  %s  # %s\n", cmd, sess.Prompt)
591→		default:
592→			fmt.Fprintf(os.Stderr, "  %s\n", cmd)
593→		}
594→	}
595→
596→	return nil
597→}
