599→// resumeSingleSession restores a single session (fallback when multi-session restore fails).
600→// Always overwrites existing session logs to ensure consistency with checkpoint state.
601→// If force is false, prompts for confirmation when local log has newer timestamps.
602→func resumeSingleSession(ctx context.Context, ag agent.Agent, sessionID string, checkpointID id.CheckpointID, repoRoot string, force bool) error {
603→	sessionLogPath, err := resolveTranscriptPath(ctx, sessionID, ag)
604→	if err != nil {
605→		return fmt.Errorf("failed to resolve transcript path: %w", err)
606→	}
607→
608→	if checkpointID.IsEmpty() {
609→		logging.Debug(ctx, "resume session: empty checkpoint ID",
610→			slog.String("checkpoint_id", checkpointID.String()),
611→		)
612→		fmt.Fprintf(os.Stderr, "Session '%s' found in commit trailer but session log not available\n", sessionID)
613→		fmt.Fprintf(os.Stderr, "\nTo continue this session, run:\n")
614→		fmt.Fprintf(os.Stderr, "  %s\n", ag.FormatResumeCommand(sessionID))
615→		return nil
616→	}
617→
618→	logContent, _, err := checkpoint.LookupSessionLog(ctx, checkpointID)
619→	if err != nil {
620→		if errors.Is(err, checkpoint.ErrCheckpointNotFound) || errors.Is(err, checkpoint.ErrNoTranscript) {
621→			logging.Debug(ctx, "resume session completed (no metadata)",
622→				slog.String("checkpoint_id", checkpointID.String()),
623→				slog.String("session_id", sessionID),
624→			)
625→			fmt.Fprintf(os.Stderr, "Session '%s' found in commit trailer but session log not available\n", sessionID)
626→			fmt.Fprintf(os.Stderr, "\nTo continue this session, run:\n")
627→			fmt.Fprintf(os.Stderr, "  %s\n", ag.FormatResumeCommand(sessionID))
628→			return nil
629→		}
630→		logging.Error(ctx, "resume session failed",
631→			slog.String("checkpoint_id", checkpointID.String()),
632→			slog.String("session_id", sessionID),
633→			slog.String("error", err.Error()),
634→		)
635→		return fmt.Errorf("failed to get session log: %w", err)
636→	}
637→
638→	// Check if local file has newer timestamps than checkpoint
639→	if !force {
640→		localTime := paths.GetLastTimestampFromFile(sessionLogPath)
641→		checkpointTime := paths.GetLastTimestampFromBytes(logContent)
642→		status := strategy.ClassifyTimestamps(localTime, checkpointTime)
643→
644→		if status == strategy.StatusLocalNewer {
645→			sessions := []strategy.SessionRestoreInfo{{
646→				SessionID:      sessionID,
647→				Status:         status,
648→				LocalTime:      localTime,
649→				CheckpointTime: checkpointTime,
650→			}}
651→			shouldOverwrite, promptErr := strategy.PromptOverwriteNewerLogs(sessions)
652→			if promptErr != nil {
653→				return fmt.Errorf("failed to get confirmation: %w", promptErr)
654→			}
655→			if !shouldOverwrite {
656→				fmt.Fprintf(os.Stderr, "Resume cancelled. Local session log preserved.\n")
657→				return nil
658→			}
659→		}
660→	}
661→
662→	// Ensure parent directory exists
663→	if err := os.MkdirAll(filepath.Dir(sessionLogPath), 0o750); err != nil {
664→		return fmt.Errorf("failed to create session directory: %w", err)
665→	}
666→
667→	agentSession := &agent.AgentSession{
668→		SessionID:  sessionID,
669→		AgentName:  ag.Name(),
670→		RepoPath:   repoRoot,
671→		SessionRef: sessionLogPath,
672→		NativeData: logContent,
673→	}
674→
675→	// Write the session using the agent's WriteSession method
676→	if err := ag.WriteSession(ctx, agentSession); err != nil {
677→		logging.Error(ctx, "resume session failed during write",
678→			slog.String("checkpoint_id", checkpointID.String()),
679→			slog.String("session_id", sessionID),
680→			slog.String("error", err.Error()),
681→		)
682→		return fmt.Errorf("failed to write session: %w", err)
683→	}
684→
685→	logging.Debug(ctx, "resume session completed",
686→		slog.String("checkpoint_id", checkpointID.String()),
687→		slog.String("session_id", sessionID),
688→	)
689→
690→	fmt.Fprintf(os.Stderr, "Session restored to: %s\n", sessionLogPath)
691→	fmt.Fprintf(os.Stderr, "Session: %s\n", sessionID)
692→	fmt.Fprintf(os.Stderr, "\nTo continue this session, run:\n")
693→	fmt.Fprintf(os.Stderr, "  %s\n", ag.FormatResumeCommand(sessionID))
694→
695→	return nil
696→}
