698→func promptFetchFromRemote(branchName string) (bool, error) {
699→	var confirmed bool
700→
701→	form := NewAccessibleForm(
702→		huh.NewGroup(
703→			huh.NewConfirm().
704→				Title(fmt.Sprintf("Branch '%s' not found locally. Fetch from origin?", branchName)).
705→				Value(&confirmed),
706→		),
707→	)
708→
709→	if err := form.Run(); err != nil {
710→		if errors.Is(err, huh.ErrUserAborted) {
711→			return false, nil
712→		}
713→		return false, fmt.Errorf("failed to get confirmation: %w", err)
714→	}
715→
716→	return confirmed, nil
717→}
