 66→// setupResumeTestRepo creates a test repository with an initial commit and optional feature branch.
 67→// Returns the repository, worktree, and commit hash. The caller should use t.Chdir(tmpDir).
 68→func setupResumeTestRepo(t *testing.T, tmpDir string, createFeatureBranch bool) (*git.Repository, *git.Worktree, plumbing.Hash) {
 69→	t.Helper()
 70→
 71→	repo, err := git.PlainInit(tmpDir, false)
 72→	if err != nil {
 73→		t.Fatalf("Failed to init repo: %v", err)
 74→	}
 75→
 76→	w, err := repo.Worktree()
 77→	if err != nil {
 78→		t.Fatalf("Failed to get worktree: %v", err)
 79→	}
 80→
 81→	testFile := filepath.Join(tmpDir, "test.txt")
 82→	if err := os.WriteFile(testFile, []byte("test content"), 0o644); err != nil {
 83→		t.Fatalf("Failed to write test file: %v", err)
 84→	}
 85→	if _, err := w.Add("test.txt"); err != nil {
 86→		t.Fatalf("Failed to add test file: %v", err)
 87→	}
 88→
 89→	commit, err := w.Commit("initial commit", &git.CommitOptions{
 90→		Author: &object.Signature{
 91→			Name:  "Test User",
 92→			Email: "test@example.com",
 93→		},
 94→	})
 95→	if err != nil {
 96→		t.Fatalf("Failed to create initial commit: %v", err)
 97→	}
 98→
 99→	if createFeatureBranch {
100→		featureRef := plumbing.NewHashReference(plumbing.NewBranchReferenceName("feature"), commit)
101→		if err := repo.Storer.SetReference(featureRef); err != nil {
102→			t.Fatalf("Failed to create feature branch: %v", err)
103→		}
104→	}
105→
106→	// Ensure entire/checkpoints/v1 branch exists
107→	if err := strategy.EnsureMetadataBranch(repo); err != nil {
108→		t.Fatalf("Failed to create metadata branch: %v", err)
109→	}
110→
111→	return repo, w, commit
112→}
