549→// TestResumeMultipleCheckpoints_SortsByCreatedAt verifies that resumeMultipleCheckpoints
550→// sorts checkpoints by CreatedAt ascending before restoring, so that the newest checkpoint
551→// writes last and wins on disk. This fixes the git CLI squash merge bug where trailers
552→// appear in reverse chronological order (newest first).
553→func TestResumeMultipleCheckpoints_SortsByCreatedAt(t *testing.T) {
554→	tmpDir := t.TempDir()
555→	t.Chdir(tmpDir)
556→
557→	repo, _, _ := setupResumeTestRepo(t, tmpDir, false)
558→
559→	// Create checkpoints with different timestamps.
560→	// Simulate git CLI squash merge order: newest first in the commit message.
561→	t1 := time.Date(2025, 1, 1, 10, 0, 0, 0, time.UTC) // oldest
562→	t2 := time.Date(2025, 1, 1, 11, 0, 0, 0, time.UTC)
563→	t3 := time.Date(2025, 1, 1, 12, 0, 0, 0, time.UTC) // newest
564→
565→	cpID1 := createCheckpointOnMetadataBranchFull(t, repo, "session-oldest", id.MustCheckpointID("aaa111bbb222"), t1)
566→	cpID2 := createCheckpointOnMetadataBranchFull(t, repo, "session-middle", id.MustCheckpointID("ccc333ddd444"), t2)
567→	cpID3 := createCheckpointOnMetadataBranchFull(t, repo, "session-newest", id.MustCheckpointID("eee555fff666"), t3)
568→
569→	metadataTree, err := strategy.GetMetadataBranchTree(repo)
570→	if err != nil {
571→		t.Fatalf("Failed to get metadata branch tree: %v", err)
572→	}
573→
574→	// Pass checkpoint IDs in reverse chronological order (newest first),
575→	// simulating git CLI squash merge trailer order.
576→	reverseOrderIDs := []id.CheckpointID{cpID3, cpID2, cpID1}
577→	checkpoints := collectCheckpointsByAge(metadataTree, reverseOrderIDs)
578→
579→	// Verify: after sorting, oldest is first, newest is last
580→	if len(checkpoints) != 3 {
581→		t.Fatalf("got %d checkpoints, want 3", len(checkpoints))
582→	}
583→	if checkpoints[0].CheckpointID.String() != cpID1.String() {
584→		t.Errorf("checkpoints[0] = %s (want oldest %s)", checkpoints[0].CheckpointID, cpID1)
585→	}
586→	if checkpoints[1].CheckpointID.String() != cpID2.String() {
587→		t.Errorf("checkpoints[1] = %s (want middle %s)", checkpoints[1].CheckpointID, cpID2)
588→	}
589→	if checkpoints[2].CheckpointID.String() != cpID3.String() {
590→		t.Errorf("checkpoints[2] = %s (want newest %s)", checkpoints[2].CheckpointID, cpID3)
591→	}
592→
593→	// Verify timestamps are actually ascending
594→	if !checkpoints[0].CreatedAt.Before(checkpoints[1].CreatedAt) {
595→		t.Errorf("checkpoints[0].CreatedAt (%v) should be before checkpoints[1].CreatedAt (%v)",
596→			checkpoints[0].CreatedAt, checkpoints[1].CreatedAt)
597→	}
598→	if !checkpoints[1].CreatedAt.Before(checkpoints[2].CreatedAt) {
599→		t.Errorf("checkpoints[1].CreatedAt (%v) should be before checkpoints[2].CreatedAt (%v)",
600→			checkpoints[1].CreatedAt, checkpoints[2].CreatedAt)
601→	}
602→}
