164→		}
165→		skipped := len(result.checkpointIDs) - 1
166→		fmt.Fprintf(os.Stderr, "Found %d checkpoints on the latest commit in this branch, resuming from the latest (%d older checkpoints skipped)\n",
167→			len(result.checkpointIDs), skipped)
