223→// collectCheckpointsByAge reads metadata for each checkpoint ID from the tree,
224→// skips any that can't be read, and returns them sorted by CreatedAt ascending.
225→// Sorting ensures the newest checkpoint is restored last and wins on disk,
226→// regardless of trailer order in the commit message.
227→func collectCheckpointsByAge(tree *object.Tree, checkpointIDs []id.CheckpointID) []*strategy.CheckpointInfo {
228→	var checkpoints []*strategy.CheckpointInfo
