251→// findBranchCheckpoints finds the most recent commit with an Entire-Checkpoint trailer
252→// among commits that are unique to this branch (not reachable from the default branch).
253→// This handles the case where main has been merged into the feature branch.
254→func findBranchCheckpoints(repo *git.Repository, branchName string) (*branchCheckpointsResult, error) {
255→	result := &branchCheckpointsResult{}
256→
257→	// Get HEAD commit
258→	head, err := repo.Head()
259→	if err != nil {
260→		return nil, fmt.Errorf("failed to get HEAD: %w", err)
261→	}
262→
263→	headCommit, err := repo.CommitObject(head.Hash())
264→	if err != nil {
265→		return nil, fmt.Errorf("failed to get HEAD commit: %w", err)
266→	}
267→
268→	// First, check if HEAD itself has a checkpoint (most common case)
269→	if cpIDs := trailers.ParseAllCheckpoints(headCommit.Message); len(cpIDs) > 0 {
270→		result.checkpointIDs = cpIDs
271→		result.commitHash = head.Hash().String()
272→		result.commitMessage = headCommit.Message
273→		result.newerCommitsExist = false
274→		return result, nil
275→	}
276→
277→	// HEAD doesn't have a checkpoint - find branch-only commits
278→	// Get the default branch name
279→	defaultBranch := getDefaultBranchFromRemote(repo)
280→	if defaultBranch == "" {
281→		// Fallback: try common names
282→		for _, name := range []string{"main", "master"} {
283→			if _, err := repo.Reference(plumbing.NewBranchReferenceName(name), true); err == nil {
284→				defaultBranch = name
285→				break
286→			}
287→		}
288→	}
289→
290→	// If we can't find a default branch, or we're on it, just walk all commits
291→	if defaultBranch == "" || defaultBranch == branchName {
292→		return findCheckpointInHistory(headCommit, nil), nil
293→	}
294→
295→	// Get the default branch reference
296→	defaultRef, err := repo.Reference(plumbing.NewBranchReferenceName(defaultBranch), true)
297→	if err != nil {
298→		// Default branch doesn't exist locally, fall back to walking all commits
299→		return findCheckpointInHistory(headCommit, nil), nil //nolint:nilerr // Intentional fallback
300→	}
301→
302→	defaultCommit, err := repo.CommitObject(defaultRef.Hash())
303→	if err != nil {
304→		// Can't get default commit, fall back to walking all commits
305→		return findCheckpointInHistory(headCommit, nil), nil //nolint:nilerr // Intentional fallback
306→	}
307→
308→	// Find merge base
309→	mergeBase, err := headCommit.MergeBase(defaultCommit)
310→	if err != nil || len(mergeBase) == 0 {
311→		// No common ancestor, fall back to walking all commits
312→		return findCheckpointInHistory(headCommit, nil), nil //nolint:nilerr // Intentional fallback
313→	}
314→
315→	// Walk from HEAD to merge base, looking for checkpoint
316→	return findCheckpointInHistory(headCommit, &mergeBase[0].Hash), nil
317→}
318→
319→// findCheckpointInHistory walks commit history from start looking for a checkpoint trailer.
320→// If stopAt is provided, stops when reaching that commit (exclusive).
321→// Returns the first checkpoint found and info about commits between HEAD and the checkpoint.
322→// It distinguishes between merge commits (bringing in other branches) and regular commits
323→// (actual branch work) to avoid false warnings after merging main.
324→func findCheckpointInHistory(start *object.Commit, stopAt *plumbing.Hash) *branchCheckpointsResult {
325→	result := &branchCheckpointsResult{}
326→	branchWorkCommits := 0 // Regular commits without checkpoints (actual work)
327→	const maxCommits = 100 // Limit search depth
328→	totalChecked := 0
329→
330→	current := start
331→	for current != nil && totalChecked < maxCommits {
332→		// Stop if we've reached the boundary
333→		if stopAt != nil && current.Hash == *stopAt {
334→			break
335→		}
336→
337→		// Check for checkpoint trailer
338→		if cpIDs := trailers.ParseAllCheckpoints(current.Message); len(cpIDs) > 0 {
339→			result.checkpointIDs = cpIDs
340→			result.commitHash = current.Hash.String()
341→			result.commitMessage = current.Message
342→			// Only warn about branch work commits, not merge commits
343→			result.newerCommitsExist = branchWorkCommits > 0
344→			result.newerCommitCount = branchWorkCommits
345→			return result
346→		}
347→
348→		// Only count regular commits (not merge commits) as "branch work"
349→		if current.NumParents() <= 1 {
350→			branchWorkCommits++
351→		}
352→
353→		totalChecked++
354→
355→		// Move to parent (first parent for merge commits - follows the main line)
356→		if current.NumParents() == 0 {
357→			break
358→		}
359→		parent, err := current.Parent(0)
360→		if err != nil {
361→			// Can't get parent, treat as end of history
362→			break
363→		}
364→		current = parent
365→	}
366→
367→	// No checkpoint found
368→	return result
369→}
