401→		return nil //nolint:nilerr // Informational message, not a fatal error
402→	}
403→
404→	// Check if the checkpoint exists on the remote
405→	metadata, err := strategy.ReadCheckpointMetadata(remoteTree, checkpointID.Path())
406→	if err != nil {
407→		fmt.Fprintf(os.Stderr, "Checkpoint '%s' found in commit but session metadata not available\n", checkpointID)
408→		return nil //nolint:nilerr // Informational message, not a fatal error
409→	}
410→
411→	// Metadata exists on remote but not locally - fetch it automatically
412→	fmt.Fprintf(os.Stderr, "Fetching session metadata from origin...\n")
413→	if err := FetchMetadataBranch(ctx); err != nil {
414→		fmt.Fprintf(os.Stderr, "Failed to fetch metadata: %v\n", err)
415→		fmt.Fprintf(os.Stderr, "You can try manually: git fetch origin entire/checkpoints/v1:entire/checkpoints/v1\n")
416→		return NewSilentError(errors.New("failed to fetch metadata"))
