423→// resumeSession restores and displays the resume command for a specific session.
424→// For multi-session checkpoints, restores ALL sessions and shows commands for each.
425→// If force is false, prompts for confirmation when local logs have newer timestamps.
426→func resumeSession(ctx context.Context, sessionID string, checkpointID id.CheckpointID, force bool) error {
427→	// Read checkpoint metadata first to get agent type (matching rewind pattern)
428→	repo, err := openRepository(ctx)
429→	if err != nil {
430→		return fmt.Errorf("failed to open repository: %w", err)
431→	}
432→
433→	metadataTree, err := strategy.GetMetadataBranchTree(repo)
434→	if err != nil {
435→		return fmt.Errorf("failed to get metadata branch: %w", err)
436→	}
437→
438→	metadata, err := strategy.ReadCheckpointMetadata(metadataTree, checkpointID.Path())
439→	if err != nil {
440→		return fmt.Errorf("failed to read checkpoint metadata: %w", err)
441→	}
442→
443→	// Resolve agent from checkpoint metadata (same as rewind)
444→	ag, err := strategy.ResolveAgentForRewind(metadata.Agent)
445→	if err != nil {
446→		return fmt.Errorf("failed to resolve agent: %w", err)
447→	}
448→
449→	// Initialize logging context with agent
450→	logCtx := logging.WithAgent(logging.WithComponent(ctx, "resume"), ag.Name())
451→
452→	logging.Debug(logCtx, "resume session started",
453→		slog.String("checkpoint_id", checkpointID.String()),
454→		slog.String("session_id", sessionID),
455→	)
456→
457→	// Get worktree root for session directory lookup
458→	repoRoot, err := paths.WorktreeRoot(ctx)
459→	if err != nil {
460→		return fmt.Errorf("failed to get worktree root: %w", err)
461→	}
462→
463→	sessionDir, err := ag.GetSessionDir(repoRoot)
464→	if err != nil {
465→		return fmt.Errorf("failed to determine session directory: %w", err)
466→	}
467→
468→	// Create directory if it doesn't exist
469→	if err := os.MkdirAll(sessionDir, 0o700); err != nil {
470→		return fmt.Errorf("failed to create session directory: %w", err)
471→	}
472→
473→	// Get strategy and restore sessions using full checkpoint data
474→	strat := GetStrategy(ctx)
475→
476→	// Use RestoreLogsOnly via LogsOnlyRestorer interface for multi-session support
477→	// Create a logs-only rewind point with Agent populated (same as rewind)
478→	point := strategy.RewindPoint{
479→		IsLogsOnly:   true,
480→		CheckpointID: checkpointID,
481→		Agent:        metadata.Agent,
482→	}
483→
484→	sessions, restoreErr := strat.RestoreLogsOnly(ctx, point, force)
485→	if restoreErr != nil || len(sessions) == 0 {
486→		// Fall back to single-session restore (e.g., old checkpoints without agent metadata)
487→		return resumeSingleSession(ctx, ag, sessionID, checkpointID, repoRoot, force)
488→	}
489→
490→	logging.Debug(logCtx, "resume session completed",
491→		slog.String("checkpoint_id", checkpointID.String()),
492→		slog.Int("session_count", len(sessions)),
493→	)
494→
495→	return displayRestoredSessions(sessions)
496→}
