498→// displayRestoredSessions sorts sessions by CreatedAt and prints resume commands.
499→// Used by both resumeSession (single checkpoint) and resumeMultipleCheckpoints (squash merge).
500→func displayRestoredSessions(sessions []strategy.RestoredSession) error {
501→	sort.SliceStable(sessions, func(i, j int) bool {
502→		return sessions[i].CreatedAt.Before(sessions[j].CreatedAt)
503→	})
504→
505→	if len(sessions) > 1 {
506→		fmt.Fprintf(os.Stderr, "\nRestored %d sessions. To continue, run:\n", len(sessions))
507→	} else if len(sessions) == 1 {
508→		fmt.Fprintf(os.Stderr, "Session: %s\n", sessions[0].SessionID)
509→		fmt.Fprintf(os.Stderr, "\nTo continue this session, run:\n")
510→	}
511→
512→	for i, sess := range sessions {
513→		sessionAgent, err := strategy.ResolveAgentForRewind(sess.Agent)
514→		if err != nil {
515→			return fmt.Errorf("failed to resolve agent for session %s: %w", sess.SessionID, err)
516→		}
517→		cmd := sessionAgent.FormatResumeCommand(sess.SessionID)
518→
519→		isLast := i == len(sessions)-1
520→		switch {
521→		case len(sessions) > 1 && isLast && sess.Prompt != "":
522→			fmt.Fprintf(os.Stderr, "  %s  # %s (most recent)\n", cmd, sess.Prompt)
523→		case len(sessions) > 1 && isLast:
524→			fmt.Fprintf(os.Stderr, "  %s  # (most recent)\n", cmd)
525→		case sess.Prompt != "":
526→			fmt.Fprintf(os.Stderr, "  %s  # %s\n", cmd, sess.Prompt)
527→		default:
528→			fmt.Fprintf(os.Stderr, "  %s\n", cmd)
529→		}
530→	}
531→
532→	return nil
533→}
