535→// resumeSingleSession restores a single session (fallback when multi-session restore fails).
536→// Always overwrites existing session logs to ensure consistency with checkpoint state.
537→// If force is false, prompts for confirmation when local log has newer timestamps.
538→func resumeSingleSession(ctx context.Context, ag agent.Agent, sessionID string, checkpointID id.CheckpointID, repoRoot string, force bool) error {
539→	sessionLogPath, err := resolveTranscriptPath(ctx, sessionID, ag)
540→	if err != nil {
541→		return fmt.Errorf("failed to resolve transcript path: %w", err)
542→	}
543→
544→	if checkpointID.IsEmpty() {
545→		logging.Debug(ctx, "resume session: empty checkpoint ID",
546→			slog.String("checkpoint_id", checkpointID.String()),
547→		)
548→		fmt.Fprintf(os.Stderr, "Session '%s' found in commit trailer but session log not available\n", sessionID)
549→		fmt.Fprintf(os.Stderr, "\nTo continue this session, run:\n")
550→		fmt.Fprintf(os.Stderr, "  %s\n", ag.FormatResumeCommand(sessionID))
551→		return nil
552→	}
553→
554→	logContent, _, err := checkpoint.LookupSessionLog(ctx, checkpointID)
555→	if err != nil {
556→		if errors.Is(err, checkpoint.ErrCheckpointNotFound) || errors.Is(err, checkpoint.ErrNoTranscript) {
557→			logging.Debug(ctx, "resume session completed (no metadata)",
558→				slog.String("checkpoint_id", checkpointID.String()),
559→				slog.String("session_id", sessionID),
560→			)
561→			fmt.Fprintf(os.Stderr, "Session '%s' found in commit trailer but session log not available\n", sessionID)
562→			fmt.Fprintf(os.Stderr, "\nTo continue this session, run:\n")
563→			fmt.Fprintf(os.Stderr, "  %s\n", ag.FormatResumeCommand(sessionID))
564→			return nil
565→		}
566→		logging.Error(ctx, "resume session failed",
567→			slog.String("checkpoint_id", checkpointID.String()),
568→			slog.String("session_id", sessionID),
569→			slog.String("error", err.Error()),
570→		)
571→		return fmt.Errorf("failed to get session log: %w", err)
572→	}
573→
574→	// Check if local file has newer timestamps than checkpoint
575→	if !force {
576→		localTime := paths.GetLastTimestampFromFile(sessionLogPath)
577→		checkpointTime := paths.GetLastTimestampFromBytes(logContent)
578→		status := strategy.ClassifyTimestamps(localTime, checkpointTime)
579→
580→		if status == strategy.StatusLocalNewer {
581→			sessions := []strategy.SessionRestoreInfo{{
582→				SessionID:      sessionID,
583→				Status:         status,
584→				LocalTime:      localTime,
585→				CheckpointTime: checkpointTime,
586→			}}
587→			shouldOverwrite, promptErr := strategy.PromptOverwriteNewerLogs(sessions)
588→			if promptErr != nil {
589→				return fmt.Errorf("failed to get confirmation: %w", promptErr)
590→			}
591→			if !shouldOverwrite {
592→				fmt.Fprintf(os.Stderr, "Resume cancelled. Local session log preserved.\n")
593→				return nil
594→			}
595→		}
596→	}
597→
598→	// Ensure parent directory exists
599→	if err := os.MkdirAll(filepath.Dir(sessionLogPath), 0o750); err != nil {
600→		return fmt.Errorf("failed to create session directory: %w", err)
601→	}
602→
603→	agentSession := &agent.AgentSession{
604→		SessionID:  sessionID,
605→		AgentName:  ag.Name(),
606→		RepoPath:   repoRoot,
607→		SessionRef: sessionLogPath,
608→		NativeData: logContent,
609→	}
610→
611→	// Write the session using the agent's WriteSession method
612→	if err := ag.WriteSession(ctx, agentSession); err != nil {
613→		logging.Error(ctx, "resume session failed during write",
614→			slog.String("checkpoint_id", checkpointID.String()),
615→			slog.String("session_id", sessionID),
616→			slog.String("error", err.Error()),
617→		)
618→		return fmt.Errorf("failed to write session: %w", err)
619→	}
620→
621→	logging.Debug(ctx, "resume session completed",
622→		slog.String("checkpoint_id", checkpointID.String()),
623→		slog.String("session_id", sessionID),
624→	)
625→
626→	fmt.Fprintf(os.Stderr, "Session restored to: %s\n", sessionLogPath)
627→	fmt.Fprintf(os.Stderr, "Session: %s\n", sessionID)
628→	fmt.Fprintf(os.Stderr, "\nTo continue this session, run:\n")
629→	fmt.Fprintf(os.Stderr, "  %s\n", ag.FormatResumeCommand(sessionID))
630→
631→	return nil
632→}
